	if result != nil {
		t.Errorf("expected nil result on error, got %v", result)
	}

	if err != transformErr {
		t.Errorf("expected encryption error, got %v", err)
	}
}

// TestPrefixTransformerContextPropagation tests that context is properly propagated
func TestPrefixTransformerContextPropagation(t *testing.T) {
	mock := &mockTransformer{
		transformFromStorageResult: []byte("result"),
	}

	transformers := []PrefixTransformer{
		{Prefix: []byte("prefix:"), Transformer: mock},
	}

	testErr := fmt.Errorf("no match")
	p := NewPrefixTransformers(testErr, transformers...)

	testCtx := context.Background()
	dataCtx := DefaultContext([]byte("auth"))

	p.TransformFromStorage(testCtx, []byte("prefix:data"), dataCtx)

	// Verify the stripped data was passed (without prefix)
	if !bytes.Equal(mock.recordedFromData, []byte("data")) {
		t.Errorf("expected stripped data to be passed, got %v", mock.recordedFromData)
	}
}

